+            manual_count.set(manual_count.get() + 1);
+            t.children.iter().any(|c| c.label == "trigger")
+        });
+
+        // The logged predicate_calls should match our manual count.
+        assert_eq!(result.predicate_calls, manual_count.get() as usize);
+    }
+}

