+
+        // Evidence array.
+        let evidence = parsed["evidence"].as_array().expect("evidence is array");
+        assert_eq!(evidence.len(), 2);
+        assert_eq!(evidence[0]["label"], "change_rate");
+        assert!(evidence[0]["bf"].as_f64().unwrap() > 0.0);
