+        // Confidence interval.
+        let ci = parsed["ci"].as_array().expect("ci is array");
+        assert_eq!(ci.len(), 2);
+        let lower = ci[0].as_f64().unwrap();
+        let upper = ci[1].as_f64().unwrap();
